INSERT INTO ingredient_knowledge (id, name, category, species_safe, safety_notes, nutrition_info, content_text) VALUES
('6ed928f3-4a13-4498-8641-7ebff8373a5b', 'chicken breast (cooked, skinless, boneless)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; serve plain (no oils/salt/seasonings). Remove skin and all bones. Use short-term in bland feeding unless diet is professionally balanced.', 'Approx per 100g: ~165 kcal; ~31 g protein; ~3.6 g fat; ~0 g carbohydrate.', 'Lean cooked chicken breast is a common bland-diet protein for dogs and cats. Ensure it is fully cooked, skinless, boneless, and unseasoned. Because simple chicken-and-rice style meals are not complete and balanced, use only short-term unless formulated by a veterinary nutrition professional.'),
('2ec37dde-6500-4bcf-86cb-c69af883a459', 'white rice (cooked, soft)', 'grain_starch', '{"DOG","CAT"}', 'Cook until soft; serve plain (no salt, oils, flavourings). For dogs, often paired with lean protein short-term. Not a long-term complete diet ingredient by itself.', 'Approx per 100g: 130 kcal; 2.7 g protein; 0.28 g fat; 28.2 g carbohydrate.', 'Cooked white rice is a frequently recommended short-term carbohydrate for bland diets in dogs, and is also used alongside meat in some veterinary guidance. It should be soft, plain, and used temporarily because rice-based home diets are nutritionally incomplete if fed long-term without formulation.'),
('a6f69330-2255-4647-81f7-6d9f2b164cb2', 'turkey breast (cooked, skinless, boneless)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; remove skin/bones; avoid seasoning and fat drippings. Use as lean protein in bland diets short-term unless balanced.', 'Approx per 100g: ~147 kcal; ~30 g protein; ~2 g fat; ~0 g carbohydrate.', 'Skinless turkey breast is a lean protein commonly listed for bland diets in dogs and cats. Serve fully cooked and plain. Avoid long-term feeding as a two-ingredient home diet unless professionally formulated and supplemented.'),
('09b18348-24ce-47bd-ae6a-fa2da90f7cb4', 'white fish fillet (poached; e.g. cod; plain)', 'seafood', '{"DOG","CAT"}', 'Poach/steam/bake plain; remove all skin and bones. Avoid oils/salt. Prefer lower-fat preparations for GI upset.', 'Approx per 100g (cooked cod): ~85 kcal; high protein; very low fat; carbohydrate ~0 g (exact values vary).', 'Plain poached white fish fillet is listed as a common bland-diet option for both dogs and cats. Ensure it is fully cooked and completely deboned to reduce choking/obstruction risk.'),
('490363f3-ed14-4078-b461-52779486c2b9', 'canned pumpkin (plain, cooked/canned)', 'vegetable', '{"DOG","CAT"}', 'Use plain pumpkin only (not sweetened pie filling). Feed in small portions; introduce gradually to reduce GI upset. Avoid seasonings.', 'Approx per 100g: ~34 kcal; low fat; modest carbohydrate; fibre present (varies by product).', 'Plain cooked/canned pumpkin is listed as a low-fat snack option for pets and is commonly used in home feeding for digestive support. Ensure it is unsweetened and unseasoned.'),
('257a8f90-3d9a-4c7c-93e9-77ae02a7f0bc', 'eggs (whole, cooked; e.g. scrambled/boiled)', 'protein', '{"DOG","CAT"}', 'Cook fully. Avoid raw eggs/meat due to bacterial risk and raw egg factors that may interfere with vitamin absorption over time. Serve plain; avoid butter/oil.', 'Approx per 100g (hard-boiled): 155 kcal; 12.6 g protein; 10.6 g fat; 1.1 g carbohydrate.', 'Cooked eggs are used in bland diets for dogs and cats. They should be fully cooked and served without added fats or seasoning. Raw egg exposure carries additional risks and is discouraged in veterinary poison-control guidance.'),
('e6c63516-4c6f-4a47-8cb3-4f72d90d0f5a', 'low-fat cottage cheese', 'dairy', '{"DOG","CAT"}', 'Use low-fat versions; introduce slowly. Many pets are lactose-intolerant—stop if diarrhoea occurs. Do not use as the sole long-term protein without formulation.', 'Approx per 100g (2%): 81 kcal; 10.5 g protein; 2.3 g fat; 4.8 g carbohydrate.', 'Low-fat cottage cheese is listed as a bland-diet option, and also appears in veterinary discussions of highly digestible home-made GI diets. Because dairy can cause digestive upset in lactose-intolerant pets, feed cautiously and in small amounts.'),
('7e20d7ab-4b2e-4c10-a0e1-060d34ef159c', 'boiled potatoes (plain)', 'grain_starch', '{"DOG","CAT"}', 'Boil until soft; serve plain. Avoid butter/oil/salt. Cool before serving. Use as bland-diet carbohydrate short-term (dogs) or per veterinary guidance.', 'Approx per 100g: ~87 kcal; ~20 g carbohydrate; ~2 g protein; ~0 g fat.', 'Plain cooked potatoes are included as a carbohydrate option in bland diets for dogs and are also referenced in veterinary elimination-diet guidance as a carbohydrate base. Keep preparation simple and avoid added fats.'),
('4c5e3e4d-e0f1-4df3-85b6-c8a22d87f5cd', 'pasta (plain, cooked)', 'grain_starch', '{"DOG","CAT"}', 'Cook plain; avoid sauces, garlic, onion, salt, oils. Cool before serving. Short-term bland use (dogs) unless balanced/formulated.', 'Unspecified (varies by pasta type and cooking).', 'Plain cooked pasta is listed as an alternative carbohydrate in bland diets for dogs. It should be served without any sauces or seasonings that could be harmful (e.g., onion/garlic).'),
('e1dcb9c8-e7b4-4b8c-a0ac-5f88080f5f7d', 'carrots (raw or cooked; plain)', 'vegetable', '{"DOG","CAT"}', 'Cut into bite-size pieces to prevent choking. Serve raw or cooked without seasonings. Introduce gradually for sensitive stomachs.', 'Unspecified (see USDA FoodData Central link).', 'Carrots are repeatedly listed as a pet-safe vegetable snack and also appear in veterinary treat guidance designed to avoid unbalancing the diet. Serve plain and in small portions.'),
('aef3c7cd-2f2f-4697-a6b9-8f236b9f886d', 'green beans (plain)', 'vegetable', '{"DOG","CAT"}', 'Serve plain (steamed/boiled, no salt) and cut appropriately. Avoid heavily salted canned products.', 'Unspecified (see USDA FoodData Central link).', 'Green beans are commonly recommended as a low-fat vegetable snack, and are also listed among low-phosphorus fresh-food treat options in veterinary nutrition guidance.'),
('e4c5fda9-8f8d-4f8b-b8ff-a3b5f37cddcf', 'broccoli (plain, steamed/boiled)', 'vegetable', '{"DOG","CAT"}', 'Serve cooked and drained; no salt/seasonings. Start with small portions to avoid gas/GI upset.', 'Unspecified (see USDA FoodData Central link).', 'Broccoli is included in vet-authored treat guidance as a low-calorie snack option. Keep preparation plain and portions modest to limit digestive upset.'),
('d0e0a2c2-8a62-4e9d-8a84-1d670e4fba6e', 'cauliflower (plain)', 'vegetable', '{"DOG","CAT"}', 'Serve plain; introduce gradually to reduce gas. Cut small to prevent choking.', 'Unspecified (see USDA FoodData Central link).', 'Cauliflower is listed as a pet-safe vegetable snack. Serve in small pieces and without seasoning.'),
('a7db7a43-7b52-4b77-98d0-52dc764dbf1c', 'celery (plain)', 'vegetable', '{"DOG","CAT"}', 'Slice small; feed as snack sizes. Avoid dips/salt/seasonings.', 'Unspecified (see USDA FoodData Central link).', 'Celery is included among pet-safe vegetable snacks. Prepare plainly and in bite-size pieces.'),
('ba6f1161-f38d-4f0d-8f32-5df03d2efcad', 'cucumber (plain)', 'vegetable', '{"DOG","CAT"}', 'Slice/chop to avoid choking. Serve plain; avoid pickled/salted forms.', 'Unspecified (see USDA FoodData Central link).', 'Cucumber is listed among pet-safe snack produce. Offer plain and in small portions.'),
('3d7c0d84-1795-4ed0-8a4c-ec7cbd05ed3f', 'zucchini (plain; steamed/boiled)', 'vegetable', '{"DOG","CAT"}', 'Serve steamed/boiled and unseasoned. Cut appropriately. Start with small portions.', 'Approx per 100g: 17 kcal; 1.2 g protein; 0.32 g fat; 3.1 g carbohydrate.', 'Zucchini appears in veterinary treat guidance as a low-calorie option (including for renal treat selection). Serve plain and portion-controlled.'),
('d0d8675d-7e72-44d4-bf84-7a39e0d1d2df', 'cabbage (boiled/drained; no salt)', 'vegetable', '{"DOG","CAT"}', 'Use boiled/drained and unseasoned to reduce GI irritation. Start small to avoid gas.', 'Unspecified (see USDA FoodData Central link).', 'Cabbage (boiled, drained, no salt) appears in veterinary treat guidance intended to provide low-calorie options without unbalancing the diet.'),
('9b3b2b95-5710-49e9-9d52-42f0a64d3f04', 'apples (no seeds/core; chopped)', 'fruit', '{"DOG","CAT"}', 'Remove core/seeds/stem; chop small. Feed in moderation to limit sugar and GI upset.', 'Unspecified (see USDA FoodData Central link).', 'Apples are listed as pet-safe fruit snacks and also appear in veterinary treat guidance for portion-controlled feeding. Prepare by removing seeds and core and offering small pieces.'),
('d0e98abe-9c05-4c19-a540-2cfead2b5f4b', 'bananas (plain)', 'fruit', '{"DOG","CAT"}', 'Offer small portions; fruit is higher in sugar than most vegetables. Remove peel.', 'Approx per 100g: ~89 kcal (macros vary).', 'Bananas are listed among pet-safe fruits; because fruits are relatively sugary, use moderation and keep portions small.'),
('65d26f98-1b1e-4d8e-a3c9-6c0e8e0d99f9', 'blueberries (plain)', 'fruit', '{"DOG","CAT"}', 'Feed as small treats; avoid sweetened products. Introduce gradually for sensitive pets.', 'Approx per 100g: ~57 kcal (values vary by blueberry type).', 'Blueberries are listed as pet-safe fruit snacks and appear in vet nutrition treat lists (including low-phosphorus fresh treat suggestions). Feed in moderation.'),
('00d3aefe-b8e1-45b0-b1fa-4f8d6322e0f1', 'strawberries (plain)', 'fruit', '{"DOG","CAT"}', 'Wash, remove stems; serve in small portions. Avoid sweetened strawberry products.', 'Unspecified (see USDA FoodData Central link).', 'Strawberries are listed as pet-safe fruit snacks and appear in vet-authored treat guidance with portion examples.'),
('1db4a8d0-7a39-47e4-8c39-59c1a0e5b5c9', 'pineapple (plain; no rind/core)', 'fruit', '{"DOG","CAT"}', 'Remove rind and tough core; offer small pieces. Avoid canned pineapple in syrup.', 'Unspecified (see USDA FoodData Central link).', 'Pineapple is listed among pet-safe fruit snacks. Prepare by removing rind/core and feeding in moderation.'),
('0b4b083b-2f41-4a80-a7f6-14b7f0c3dba0', 'cantaloupe (plain; no rind/seeds)', 'fruit', '{"DOG","CAT"}', 'Remove rind/seeds; cut into small pieces; feed in moderation.', 'Unspecified (see USDA FoodData Central link).', 'Cantaloupe is listed as a pet-safe fruit snack when prepared appropriately and fed in small portions.'),
('75c4a355-42d9-4d59-8c53-6ef94fef88a3', 'kiwi (plain; peeled)', 'fruit', '{"DOG","CAT"}', 'Peel and slice; feed small portions; discontinue if GI upset occurs.', 'Unspecified (see USDA FoodData Central link).', 'Kiwi appears on pet-safe fruit snack lists. Offer peeled pieces in moderation.'),
('7cbcd92f-6f0d-46e1-bf9b-1e8b0c1d6f4a', 'watermelon (seedless; no rind)', 'fruit', '{"DOG","CAT"}', 'Remove rind and seeds; offer small portions. Useful as a hydrating low-phosphorus fresh treat option in some vet guidance.', 'Unspecified (see USDA FoodData Central link).', 'Watermelon is listed in veterinary nutrition guidance as a fresh food treat option (including in renal-treat discussions). Serve seedless flesh only and keep portions modest.'),
('5ca40c8a-6b2e-4d33-91f3-07eebae4a35b', 'peaches (plain; pit removed)', 'fruit', '{"DOG","CAT"}', 'Remove pit; cut into small pieces; feed in moderation due to sugar.', 'Unspecified (see USDA FoodData Central link).', 'Peaches appear in veterinary guidance discussing pet-safe fruits and vegetables; remove the pit and offer small amounts only.'),
('2f3d8f46-29b1-4d9c-b10b-0a1e3cbdde54', 'cheddar cheese (small amounts)', 'dairy', '{"DOG","CAT"}', 'Feed sparingly due to fat and lactose; stop if diarrhoea occurs. Avoid flavoured cheeses with onion/garlic. Use tiny portions as treat/pill disguise.', 'Approx per 100g: ~403 kcal; ~23 g protein; ~33 g fat; ~3 g carbohydrate.', 'Cheese is listed as an occasional pet-safe snack, typically in small cubes. Because many pets have limited lactase and dairy can trigger digestive upset, treat as an infrequent high-fat snack.'),
('e1642e1f-5c0f-4d7e-bb3a-60b56b8d2f7b', 'peanut butter (smooth; xylitol-free)', 'treat', '{"DOG","CAT"}', 'Check labels to ensure NO xylitol (hazardous to dogs). Feed small amounts due to high fat; avoid sweetened/flavoured varieties.', 'Approx per 100g: ~588 kcal; ~49.5 g fat; ~24 g carbohydrate; ~21.9 g protein.', 'Peanut butter is commonly used as a treat or to hide medication. The key safety step is verifying it contains no xylitol, which can cause severe hypoglycaemia and liver injury in dogs. Portion-control is essential due to fat content.'),
('8b10e1a2-6200-4b6e-b8fb-49a0e47a0950', 'popcorn (air-popped; no butter/salt)', 'treat', '{"DOG","CAT"}', 'Use air-popped only; avoid butter, oils, salt, flavouring powders. Offer a few pieces only; supervise (choking risk).', 'Approx per 100g: 387 kcal; 12.9 g protein; 4.5 g fat; 77.8 g carbohydrate (high fibre).', 'Air-popped popcorn is listed as a pet-safe snack when it is prepared without added fats or salt. Because it is dry and crunchy, feed a small amount and supervise to reduce choking risk.'),
('efb36dc3-8b90-4b2b-aca1-7a7ed771eeb1', 'chicken thigh (cooked, skinless, boneless)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; remove skin/bones. Higher fat than breast—use caution for pancreatitis-prone pets and in bland diets intended to be low-fat.', 'Unspecified (see USDA FoodData Central link; values vary by trim and cooking).', 'Chicken thigh meat is explicitly noted in veterinary guidance as higher-fat compared with breast meat; this matters when attempting a low-fat bland diet. Prepare plain and deboned.'),
('6b0c2e5b-9d5a-4dc8-86f8-64d7b8f8a22e', 'lean ground beef (cooked; plain)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly and drain fat; serve plain. Avoid onions/garlic and avoid high-fat versions for pancreatitis-prone pets.', 'Unspecified (see USDA FoodData Central link).', 'Lean ground beef is listed as an alternative lean protein option in some bland-diet instructions. Choose lean cuts and drain fat after cooking.'),
('0d3a5ab7-8f23-4d71-9d6a-1f3d05a3113a', 'pork loin (lean, cooked; plain)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; choose lean loin; avoid seasonings and high-salt processed pork. Serve small portions.', 'Unspecified (see USDA FoodData Central link).', 'Lean cooked pork is listed as a pet-safe meat in guidance on sharing foods with pets, and lean pork loin appears as a bland-diet substitution in some veterinary hospital handouts. Prepare plain and portion-control.'),
('6d455eec-81b6-4c8b-86cf-7a2d6c6d0d3e', 'egg whites (cooked)', 'protein', '{"DOG","CAT"}', 'Cook fully; serve plain. Often selected for lower-fat/leaner protein approaches; do not rely on egg whites alone long-term without formulation.', 'Unspecified (see USDA FoodData Central link).', 'Egg whites are used in some bland-diet substitution lists as a lean protein option. Serve fully cooked and without added fats.'),
('5f0f6b5a-4c6f-4b83-9f08-3a1eaa7d6b5c', 'brown rice (cooked, soft)', 'grain_starch', '{"DOG","CAT"}', 'Cook until soft; serve plain. Used as bland-diet carbohydrate option for dogs; not for long-term feeding unless balanced.', 'Unspecified (see USDA FoodData Central link).', 'Brown rice is explicitly listed as an option in bland diets for dogs. As with any single carbohydrate base, it should not be used as the cornerstone of a long-term home diet unless properly formulated.'),
('1a9fefc3-9e5d-4c85-8b6b-8e2ac0f4d8a1', 'lamb (cooked; novel protein option)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; serve plain. Used for elimination/hypoallergenic trials as a novel protein; must be the only diet source during the trial per veterinary guidance.', 'Unspecified (see USDA FoodData Central link).', 'Lamb is listed among novel protein sources used for hypoallergenic/elimination diet trials in dogs and cats. In such trials, strict exclusivity is required—no treats or flavoured supplements—until the assessment period is completed.'),
('dfb8a6e7-6e4c-4c0e-9f06-9c0af4a4b3d2', 'rabbit (cooked; novel protein option)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; serve plain. Appropriate for elimination trials as novel protein; ensure diet is balanced if used beyond trial.', 'Unspecified (see USDA FoodData Central link).', 'Rabbit is listed as a limited-antigen protein option for dogs and cats in veterinary GI/hypoallergenic diet discussions. Use under veterinary direction, especially for long-term feeding.'),
('f5d2b8a1-9c3e-4a0b-8f7d-2b4b6e7d8a9c', 'venison (cooked; novel protein option)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; serve plain. Used for elimination diets; ensure exclusivity during trial and balance for long-term feeding.', 'Unspecified (see USDA FoodData Central link).', 'Venison is listed as a novel protein option in veterinary hypoallergenic diet management discussions. It may support elimination-trial design when selected as a protein the patient has not previously eaten.'),
('0b5f7d8a-9c3e-4b6a-8f7d-2b4c6d7e8f9a', 'duck (cooked; novel protein option)', 'protein', '{"DOG","CAT"}', 'Cook thoroughly; remove bones/skin. Duck can be higher in fat; avoid heavy fats for pancreatitis-prone pets.', 'Unspecified (see USDA FoodData Central link).', 'Duck is listed among novel protein choices for veterinary hypoallergenic trials. Depending on cut, fat may be higher, so trim skin and consider the patient’s fat tolerance.'),
('8a9c0b5f-7d8a-4c3e-9b6a-2f7d8a9c3e4b', 'tofu (plain; alternative protein in some trials)', 'protein', '{"DOG","CAT"}', 'Use plain tofu only; avoid flavoured/seasoned products. Do not use as a long-term primary diet ingredient for cats without professional formulation.', 'Unspecified (see USDA FoodData Central link; varies by firmness).', 'Veterinary GI proceedings note tofu as a potential protein source in home-prepared elimination diets (paired with rice or potatoes). Long-term use must be fully balanced, especially for cats.'),
('b6a2f7d8-9c3e-4b0f-8a9c-7d8a9c3e4b5f', 'chicken liver (cooked; organ meat)', 'organ', '{"DOG","CAT"}', 'Feed only occasionally and in small amounts. Chronic liver feeding can contribute to vitamin A toxicity; avoid raw liver and avoid high vitamin-A supplements unless prescribed.', 'Unspecified (see USDA FoodData Central link).', 'Liver is nutrient-dense but must be portion-controlled. Veterinary guidance notes vitamin A poisoning can occur when pets are fed raw liver (or other vitamin-A rich sources) over weeks to months. This is particularly important in cats.'),
('c3e4b5f6-7d8a-4b0f-9c3e-8a9c7d8a9c3e', 'beef liver (cooked; organ meat)', 'organ', '{"DOG","CAT"}', 'Feed sparingly. Repeated high-liver diets can cause hypervitaminosis A in cats (and toxicity risk in dogs). Avoid raw liver as a routine food.', 'Unspecified (see USDA FoodData Central link).', 'Beef liver is often overrepresented in problematic home diets because it is palatable and nutrient-dense. Veterinary sources note vitamin A toxicity can develop in cats whose diets include large quantities of liver.'),
('9c3e4b5f-7d8a-4b0f-8a9c-3e4b5f7d8a9c', 'salmon (fully cooked; no bones)', 'seafood', '{"DOG","CAT"}', 'Never feed raw or undercooked salmonids to dogs in endemic regions due to salmon poisoning disease risk; cook thoroughly. Remove all bones; avoid seasoning.', 'Approx per 100g (cooked Atlantic salmon): ~206 kcal; ~22 g protein; ~12 g fat; ~0 g carbohydrate (varies by type).', 'Salmon can be used as a cooked protein source, but veterinary guidance warns that dogs may develop salmon poisoning disease after eating raw or undercooked salmonids infected with specific parasites/bacteria. Cook thoroughly and debone completely.'),
('4b5f7d8a-9c3e-4b0f-8a9c-3e4b5f7d8a90', 'fish oil (omega-3 supplement; EPA/DHA)', 'supplement', '{"DOG","CAT"}', 'Use veterinary guidance for dosing and product selection. Monitor for GI upset; avoid excess vitamin-A rich sources (e.g., cod liver oil) unless prescribed.', 'Approx per 100g: ~1000 kcal; essentially fat (values vary by product).', 'Fish oil is a supplement derived from cold-water fish and is rich in omega-3 fatty acids such as EPA and DHA. It may be used clinically for specific indications, but should be dosed appropriately with veterinary oversight.'),
('7d8a9c3e-4b5f-4b0f-8a9c-3e4b5f7d8a91', 'taurine (amino acid supplement; cats)', 'supplement', '{"CAT"}', 'Cats require dietary taurine; supplementation may be indicated for cats not receiving most nutrition from a complete commercial cat food. Use veterinary guidance for dosing and diagnosis.', 'Unspecified (supplement dosing depends on formulation; consult veterinary source).', 'Taurine is essential in feline nutrition. Veterinary sources note all cats require taurine in the diet, and supplemental taurine is recommended in certain situations—particularly if a cat is not eating a complete, high-quality commercial cat food or has specific health conditions.'),
('8a9c3e4b-5f7d-4b0f-9c3e-4b5f7d8a9c30', 'onion (all forms)', 'toxic/hazard', '{}', 'Toxic to dogs and cats. Avoid raw, cooked, powdered, or dehydrated forms. Risk includes GI irritation and red blood cell damage leading to anaemia.', 'N/A (do not feed).', 'Onion is a high-priority exclusion in any pet recipe. Veterinary poison control notes Allium species (including onion) can cause gastrointestinal irritation and red blood cell damage, with cats more susceptible though dogs are also at risk.'),
('9c3e4b5f-7d8a-4b0f-8a9c-3e4b5f7d8a31', 'garlic (all forms)', 'toxic/hazard', '{}', 'Toxic to dogs and cats. Avoid raw, cooked, powdered, or dehydrated forms. Can cause GI irritation and red blood cell damage leading to anaemia.', 'N/A (do not feed).', 'Garlic is an Allium and should be excluded from pet recipes. Veterinary poison control notes Allium species can cause GI irritation and red blood cell damage, potentially leading to anaemia.'),
('3e4b5f7d-8a9c-4b0f-9c3e-4b5f7d8a9c32', 'grapes', 'toxic/hazard', '{}', 'Avoid entirely. Associated with kidney injury/failure in dogs; toxicity is variable. Treat as an emergency ingestion.', 'N/A (do not feed).', 'Grapes are listed as a significant toxic hazard for dogs. Veterinary references report ingestion has caused kidney failure in some dogs, with variability in effect; therefore grapes are not permitted in any pet recipe.'),
('4b5f7d8a-9c3e-4b0f-8a9c-3e4b5f7d8a33', 'raisins', 'toxic/hazard', '{}', 'Avoid entirely. Associated with kidney injury/failure in dogs; toxicity is variable. Emergency ingestion.', 'N/A (do not feed).', 'Raisins are a high-risk toxic food, with veterinary sources noting kidney failure has occurred after ingestion in some dogs. Exclude from all homemade pet foods and treats.'),
('5f7d8a9c-3e4b-4b0f-9c3e-4b5f7d8a9c34', 'chocolate (all forms; dark/baking highest risk)', 'toxic/hazard', '{}', 'Toxic to dogs and cats. Methylxanthines can cause GI signs, hyperactivity, abnormal heart rhythm, tremors, seizures, and death. Dark/baking chocolate is highest risk.', 'N/A (do not feed).', 'Chocolate is a core exclusion from any pet recipe. Veterinary poison control guidance attributes toxicity to methylxanthines, with greater risk at higher cacao concentration.'),
('7d8a9c3e-4b5f-4b0f-8a9c-3e4b5f7d8a35', 'xylitol (sweetener in some peanut butters and sugar-free foods)', 'toxic/hazard', '{}', 'Highly dangerous to dogs. Can cause rapid hypoglycaemia and liver injury/failure. Check peanut butter and other products for xylitol.', 'N/A (do not feed).', 'Xylitol is a sugar alcohol sweetener that has caused severe hypoglycaemia and liver injury in dogs after ingestion. It is a critical label-check item when using peanut butter or other human foods in any pet recipe.'),
('74fd0024-15bd-436c-bea7-39e93b903fba','Sardines','Essential Fat','{"DOG","CAT"}', 'Feed plain sardines in water with no salt added; watch total fat in pancreatitis-prone pets and monitor bones if not fully softened.', 'Rich in EPA/DHA, vitamin D, calcium if bones are included, and highly bioavailable animal protein.', 'Used to increase omega-3 intake, improve palatability, and support skin, coat, and anti-inflammatory nutrition in homemade diets.'),
('5f70c28f-1314-4f65-b128-53697772f373','Mackerel','Essential Fat','{"DOG","CAT"}', 'Use cooked, plain portions and avoid heavily salted or smoked products; high fat content may not suit some GI-sensitive pets.', 'Provides concentrated marine omega-3 fatty acids, vitamin D, selenium, and complete protein.', 'Useful when formulating energy-dense diets or adding EPA/DHA support for dermatologic and inflammatory conditions.'),
('8f10dafe-e295-4d34-8b66-988e63c17f9f','Herring','Essential Fat','{"DOG","CAT"}', 'Serve cooked and unseasoned; avoid preserved products with excess sodium.', 'High in EPA/DHA, vitamin D, B12, and digestible animal protein.', 'Included as a marine fat source to improve omega-3 intake and diversify protein exposure.'),
('d8d68612-0fe6-4562-ab43-cbb926072dd8','Cod','Lean Protein','{"DOG","CAT"}', 'Cook thoroughly and remove all bones; lean fish may require extra fat balancing in long-term formulations.', 'Very lean protein source with selenium, iodine, B12, and low total fat.', 'Useful in low-fat homemade diets and in cases where a bland, highly digestible protein is preferred.'),
('d3726316-eb41-4a6e-8c30-75f70fd94d52','Tilapia','Lean Protein','{"DOG","CAT"}', 'Serve cooked, plain, and boneless; not a meaningful omega-3 source compared with oily fish.', 'Provides digestible protein, phosphorus, selenium, and low-to-moderate fat.', 'Frequently used in low-fat or GI-sensitive diet planning as a mild, lean protein option.'),
('ae4b3b0d-c3f2-43f0-aec1-fde1b9ec5d7f','Pollock','Lean Protein','{"DOG","CAT"}', 'Cook thoroughly and debone fully.', 'Lean fish protein with selenium, phosphorus, and low fat.', 'Can be used in rotation with other lean proteins in low-fat homemade recipes.'),
('83d0ce73-f8bf-4a39-b76c-c4ff17b086ae','Catfish','Muscle Protein','{"DOG","CAT"}', 'Plain cooked portions only; moderate fat content may be unsuitable for some low-fat plans.', 'Contains protein, phosphorus, B12, and moderate fat.', 'Used as a palatable alternative fish protein in rotation diets.'),
('c63175df-0fd9-40b7-a48c-1e0b0e8b8818','Tuna','Muscle Protein','{"DOG","CAT"}', 'Use only plain cooked tuna or canned tuna in water occasionally; avoid chronic heavy use due to nutrient imbalance and mercury concerns.', 'Protein-dense with selenium, niacin, and phosphorus; not a balanced sole food.', 'Best used sparingly to increase palatability rather than as a long-term staple ingredient.'),
('5095592f-fb8e-497c-89e2-9ea0fdd28780','Anchovies','Essential Fat','{"DOG","CAT"}', 'Very salty preserved anchovies are not appropriate; choose plain, unsalted forms only.', 'Concentrated source of omega-3, calcium if bones are included, and animal protein.', 'Used in tiny quantities to enrich flavor and omega-3 intake.'),
('7159c126-3510-41dd-aefc-fca95ebd7e74','Mussels','Muscle Protein','{"DOG","CAT"}', 'Cook thoroughly and avoid shell fragments; use cautiously in iodine-sensitive situations.', 'Provide protein, manganese, zinc, B12, and marine lipids.', 'Useful as a trace-mineral-rich seafood ingredient and sometimes included for joint-supportive feeding strategies.'),
('53af4be7-d0ee-42dd-8e1f-c1b8dc0b7f4f','Oysters','Muscle Protein','{"DOG","CAT"}', 'Feed cooked only; shell fragments and raw contamination are risks.', 'Very rich in zinc, copper, B12, and protein.', 'Can support trace mineral density in small amounts but should be portion-controlled due to copper load.'),
('93f8bf31-e8b1-47d5-9d4c-5e2a5c5b8c80','Shrimp','Muscle Protein','{"DOG","CAT"}', 'Cook fully and remove shell, tail, and vein; avoid seasoned or salted products.', 'Lean protein with selenium, iodine, B12, and low fat.', 'Used as a highly palatable seafood protein in rotation diets.'),
('95b9354e-06a7-4b91-b734-29e7ffeb1b1a','Crab Meat','Muscle Protein','{"DOG","CAT"}', 'Use plain cooked crab only; avoid butter, seasoning, and excess sodium.', 'Provides protein, zinc, copper, selenium, and B12.', 'Can diversify protein sources in small quantities when tolerated.'),
('a51f2aaf-d723-4984-9b65-c2ef6f96adbf','Lobster Meat','Muscle Protein','{"DOG","CAT"}', 'Only plain cooked meat is acceptable; avoid rich sauces and salted preparations.', 'Protein source containing zinc, copper, selenium, and B12.', 'Occasionally used for protein variety in highly palatable recipes.'),
('54d37a18-4736-4401-ad70-29d74e85588f','Scallops','Lean Protein','{"DOG","CAT"}', 'Cook thoroughly and avoid butter-based preparation.', 'Lean seafood protein with B12, phosphorus, and selenium.', 'Useful in protein-rotation diets where lean seafood is desired.'),
('a4d425e9-3700-4f70-b1ea-9880ae7585a3','Clams','Muscle Protein','{"DOG","CAT"}', 'Cook fully and avoid shell fragments and brined products.', 'Rich in iron, B12, copper, and protein.', 'Included in small amounts to improve trace mineral density and palatability.'),
('072dccaa-3f5d-4a46-b678-d32405887785','Beef Spleen','Organ Meat','{"DOG","CAT"}', 'Feed moderately as part of organ allocation; rich organs should not dominate the recipe.', 'High in iron, B12, protein, and other hematinic nutrients.', 'Used in organ rotation to enhance iron intake and nutrient diversity.'),
('a27d1f74-7f72-4c01-9621-707b7410cad8','Lamb Spleen','Organ Meat','{"DOG","CAT"}', 'Portion-control due to rich micronutrient density.', 'Contains iron, B vitamins, and protein.', 'Useful in rotational homemade plans when organ variety is desired.'),
('14ef4661-7e4f-4548-93ac-1d530dbbdf0c','Pork Heart','Muscle Protein','{"DOG","CAT"}', 'Feed plain and cooked or from hygienic raw systems; account for phosphorus in renal patients.', 'High in taurine relative to many meats, plus iron, zinc, CoQ10-related tissue nutrients, and protein.', 'Used to add muscle meat diversity and support amino acid density in homemade carnivore-focused formulas.'),
('e68f596d-b0cc-4700-b939-c5768af0af74','Lamb Heart','Muscle Protein','{"DOG","CAT"}', 'Use as muscle meat rather than secreting organ in recipe balance.', 'Rich in protein, iron, taurine, and B vitamins.', 'Valuable in feline and canine diets needing robust animal amino acid content.'),
('fd9fbd8d-3354-49e2-aad4-1ee678e7c885','Turkey Heart','Muscle Protein','{"DOG","CAT"}', 'Count as muscle meat; not a replacement for balanced supplementation.', 'Protein-rich with iron, zinc, taurine, and B vitamins.', 'Useful in homemade formulas for palatability and amino acid diversity.'),
('b0fa5bb9-fb78-49f0-a3ff-73846ab33b66','Duck Heart','Muscle Protein','{"DOG","CAT"}', 'Moderate fat level compared with very lean meats.', 'Contains protein, iron, taurine, and B-complex vitamins.', 'Included to diversify amino acid sources in homemade meat blends.'),
('6757e7cd-f66d-4d87-8a6d-3f340f3eb572','Chicken Heart','Muscle Protein','{"DOG","CAT"}', 'Use plain and hygienically prepared.', 'Contains protein, taurine, iron, zinc, and B vitamins.', 'Commonly used in feline-oriented homemade diets to improve taurine-rich animal tissue intake.'),
('8fb3078f-0e61-4558-becf-fcecb39cbab8','Beef Brain','Organ Meat','{"DOG","CAT"}', 'High fat and fragile tissue; use sparingly and source carefully.', 'Rich in lipids, cholesterol, phospholipids, and some DHA-related neural fats.', 'Occasionally used in raw-style rotational diets, but not a staple due to richness.'),
('5ad371dd-7106-4bc1-b4a7-7f31e1911433','Pork Brain','Organ Meat','{"DOG","CAT"}', 'Use only if safely sourced and properly handled; high fat content requires moderation.', 'High lipid organ with phosphorus and cholesterol.', 'Included rarely in advanced rotational plans for tissue variety.'),
('7f508f30-c1f7-4c5c-a78c-b8abf16fc40d','Chicken Neck (Ground)','Bone Source','{"DOG","CAT"}', 'Whole necks pose choking and obstruction risks; use ground only if included.', 'Provides calcium, phosphorus, collagen, and protein when finely ground.', 'Used in raw-style formulations as a bone-inclusive calcium source where safe grinding is available.'),
('7c5519c2-7f42-4db6-8569-d5d814cd42b8','Turkey Neck (Ground)','Bone Source','{"DOG","CAT"}', 'Ground use only; whole necks are a hazard for many pets.', 'Bone-derived calcium and phosphorus with connective tissue protein.', 'Supports skeletal mineral balance in bone-inclusive formulations.'),
('a2f3155d-5150-47c0-a45d-8c5d4ec8af5d','Duck Neck (Ground)','Bone Source','{"DOG","CAT"}', 'Ground only; balance carefully against total calcium requirements.', 'Provides calcium, phosphorus, and connective tissue components.', 'Used where a ground raw mineral source is intentionally incorporated.'),
('8c3ec2e8-bb54-4682-877d-739fa1bfe74d','Chicken Frame (Ground)','Bone Source','{"DOG","CAT"}', 'Requires reliable grinding and formulation control to prevent calcium excess.', 'Bone-heavy source of calcium and phosphorus.', 'Applied in bone-inclusive recipes where mineral ratios are calculated carefully.'),
('a1af6ac2-c794-4d42-9375-72a639c7f210','Duck Frame (Ground)','Bone Source','{"DOG","CAT"}', 'Use only in finely ground form and not as a casual table-food ingredient.', 'High in structural minerals including calcium and phosphorus.', 'Supports mineralization in raw-style recipes when balanced against meat content.'),
('1c607c3b-362c-4e91-b63b-6fdd5968d0f8','Salmon Skin','Essential Fat','{"DOG","CAT"}', 'Very high fat; avoid for pancreatitis-prone or obese pets and ensure it is fully cooked.', 'Concentrated in marine fats including EPA/DHA and calories.', 'Used in small amounts to increase energy density and omega-3 content.'),
('bf80c90b-85ff-437e-af2b-6e8605ae58ce','Chicken Skin','Essential Fat','{"DOG","CAT"}', 'High fat and calorie dense; generally unsuitable for therapeutic low-fat diets.', 'Provides animal fat and energy but limited micronutrient density relative to calorie load.', 'Occasionally used to raise caloric density in high-energy canine diets.'),
('0c72aa4b-d5bc-4f36-b08d-a97d1842d318','Beef Fat Trimmings','Essential Fat','{"DOG"}', 'Use sparingly; high fat can precipitate GI upset or pancreatitis.', 'Dense source of saturated and monounsaturated fat with minimal micronutrients.', 'Added cautiously in performance or underweight dog diets when more energy density is needed.'),
('da245b82-7d4b-4d2c-a3ef-b4141f6da69e','Duck Fat','Essential Fat','{"DOG","CAT"}', 'Very energy dense; not suitable for low-fat therapeutic diets.', 'Provides concentrated dietary fat and calories.', 'Can raise palatability and energy density in selected formulations.'),
('6d3ce04c-f5be-44a8-9aa5-59c3d8b0a236','Beef Tallow','Essential Fat','{"DOG"}', 'Not appropriate for many clinical diets requiring fat restriction.', 'Rendered animal fat providing dense caloric support.', 'May be used in small amounts for high-workload canine formulations.'),
('09f4e7b0-3147-4c55-aee0-f6aef7b638af','Olive Oil','Essential Fat','{"DOG","CAT"}', 'Do not overuse; it provides calories without complete essential fatty acid coverage.', 'Rich in monounsaturated fat with modest vitamin E.', 'Occasionally used to improve palatability or raise calories, but not as a complete essential fat strategy.'),
('c6f6853a-54a3-4f6c-8f08-0f9fa7ed8393','Chia Seeds','Essential Fat','{"DOG"}', 'Introduce gradually due to fiber and water-binding effects; not a marine omega-3 substitute for cats.', 'Provide ALA, fiber, magnesium, and plant protein.', 'Used in some canine homemade diets for fiber support and plant omega contribution.'),
('48885506-d79f-4720-8a55-78aa9734ec18','Ground Flaxseed','Essential Fat','{"DOG"}', 'Can loosen stools in excess; cats convert ALA poorly to EPA/DHA.', 'Source of ALA, lignans, and soluble/insoluble fiber.', 'Often used in dog diets to add fiber and plant-based omega-3 precursors.'),
('c20e90e8-6ee7-4b1b-81c3-f7aa4146cd2a','Pumpkin Seeds','Supplement','{"DOG"}', 'Use unsalted, plain, ground forms only and in modest amounts.', 'Contain zinc, magnesium, manganese, and fat.', 'May support trace mineral intake and add dietary diversity in dog formulations.'),
('f44d4f17-5c13-4667-a858-f48f65e1453d','Sesame Seeds','Supplement','{"DOG"}', 'Use ground to improve access and only in small amounts because of calorie density.', 'Provide calcium, copper, manganese, and fat, though mineral bioavailability is variable.', 'Used sparingly where plant mineral enrichment is desired.'),
('7304de12-86d6-498c-8052-f2bf517f2907','Hemp Hearts','Essential Fat','{"DOG"}', 'Energy dense; portion control required.', 'Provide fat, plant protein, magnesium, and essential fatty acids.', 'Used in selected canine diets for added calories and fat diversity.'),
('91397a60-fd2a-4f2d-9f7e-ea96e869ba86','Plain Yogurt','Supplement','{"DOG","CAT"}', 'Many pets are lactose sensitive; use small amounts only and avoid sweetened products.', 'Provides protein, calcium, and live cultures depending on product.', 'Sometimes used as a palatable carrier or mild probiotic-support ingredient when tolerated.'),
('f4ac0048-706b-41b3-9300-f8ed8ea72ece','Kefir','Supplement','{"DOG","CAT"}', 'Introduce slowly due to fermentation-related GI sensitivity and residual lactose variability.', 'Contains live cultures, protein, calcium, and B vitamins.', 'Used in small amounts as a fermented dairy adjunct in gut-supportive feeding approaches.'),
('253d3de6-9293-426f-ab38-7461bf2f73ee','Goat Milk','Supplement','{"DOG","CAT"}', 'Still contains lactose and should not replace balanced milk replacers or complete diets.', 'Supplies water, fat, calcium, and protein.', 'Used only occasionally for palatability or short-term supplementation where tolerated.'),
('31ccf470-b41e-4efe-b8f8-096abf9380c4','Cottage Cheese','Supplement','{"DOG","CAT"}', 'Use low-fat forms when appropriate; lactose intolerance can limit use.', 'Provides protein, calcium, and relatively low fat in reduced-fat versions.', 'Useful as a highly palatable adjunct protein in bland or transitional feeding.'),
('278f737a-17aa-41ff-a710-990ab3af76ce','Ricotta','Supplement','{"DOG","CAT"}', 'Higher fat and lactose than some other dairy options; use sparingly.', 'Provides protein, calcium, and fat.', 'Can increase palatability in small amounts for selected pets.'),
('fe8d90ee-c46c-4bfe-b90d-3830f529af43','Tofu','Complex Carb','{"DOG"}', 'Use plain only; not ideal as a primary long-term protein in cat diets.', 'Supplies plant protein, calcium in some preparations, and modest fat.', 'Can be used in canine elimination-style or low-animal-protein strategies where formulation is carefully balanced.'),
('b464c02d-a85f-4f44-9dc6-4891583ea83f','Tempeh','Complex Carb','{"DOG"}', 'Fermented soy can still cause GI upset in some animals; use plain only.', 'Provides plant protein, phosphorus, and fiber.', 'Occasionally used in advanced canine recipes requiring soy-based protein diversity.'),
('5121a31d-9c7c-48d4-9825-e8e49d69757f','White Rice','Complex Carb','{"DOG","CAT"}', 'Use cooked and plain; not complete as a stand-alone long-term base.', 'Highly digestible carbohydrate with low fiber and modest B-vitamin content depending on enrichment.', 'Used in bland diets and transitional feeding because of its digestibility and low residue.'),
('8a541367-4f0e-471e-95c0-24f3f2d78975','Brown Rice','Complex Carb','{"DOG"}', 'Higher fiber than white rice and may be less suitable during acute GI upset.', 'Provides carbohydrate, manganese, magnesium, and more fiber than white rice.', 'Used in canine homemade diets when a whole-grain carbohydrate source is desired.'),
('c9f60a8a-4253-4648-a245-5edbb0354eff','Rice Noodles','Complex Carb','{"DOG","CAT"}', 'Serve plain and well cooked; avoid sauces and seasonings.', 'Primarily starch with low fat and low fiber.', 'Useful as an alternative bland carbohydrate in sensitive diets.'),
('b2db589c-58e8-4851-a89a-927786cd85eb','Plain Pasta','Complex Carb','{"DOG","CAT"}', 'Cook plain only; avoid garlic, onion, and sauce exposure.', 'Digestible starch source with modest protein depending on wheat content.', 'Sometimes used as a temporary digestible carbohydrate base in transitional feeding.'),
('d524bf00-f362-482f-8197-188435049dfe','Pearl Couscous','Complex Carb','{"DOG"}', 'Wheat-based; avoid in gluten-sensitive cases and serve plain.', 'Provides starch, some protein, and small amounts of minerals.', 'Can diversify carbohydrate sources in canine homemade diets.'),
('5eff65c9-c831-46e8-956a-e54d84b37632','Buckwheat','Complex Carb','{"DOG"}', 'Introduce gradually if the pet is not used to higher-fiber grains.', 'Provides carbohydrate, manganese, magnesium, and some rutin-related phytonutrients.', 'Alternative grain-like carbohydrate used in rotational canine recipes.'),
('83fcbd31-0d4d-4ef7-b472-774124636127','Amaranth','Complex Carb','{"DOG"}', 'Higher fiber and plant protein may reduce digestibility for some pets if overused.', 'Contains carbohydrate, plant protein, magnesium, and manganese.', 'Used to diversify carbohydrate and plant nutrient exposure in dog diets.'),
('5cb29b5d-2148-4781-b133-bf38d85073b2','Polenta','Complex Carb','{"DOG"}', 'Serve plain and cooked soft; do not use seasoned forms.', 'Corn-derived starch with modest carotenoids depending on processing.', 'Can act as an alternative digestible carbohydrate base in canine recipes.'),
('7ce9322f-7eb4-4fba-8bd6-54f1a1009b5d','Pumpkin Puree','Complex Carb','{"DOG","CAT"}', 'Use plain unsweetened puree only, not pie filling; excessive use may loosen stools or distort balance.', 'Provides soluble fiber, beta-carotene, potassium, and low calorie bulk.', 'Used to support stool quality and add fiber in GI-sensitive feeding.'),
