('2247499f-fb65-4bde-8fb3-063513e5d2ab','Inulin','Soluble Fiber','{"DOG","CAT"}', 'Excess may cause gas or loose stool.', 'Prebiotic fermentable fiber supporting beneficial gut microbes.', 'Included in small amounts to support microbiome-focused homemade formulations.'),
('6df70e40-e240-4ff1-a2d9-47c453c9f9d5','Fructooligosaccharides','Soluble Fiber','{"DOG","CAT"}', 'Use low inclusion rates to avoid GI intolerance.', 'Prebiotic oligosaccharides supporting select colonic bacteria.', 'Used to support gut health and stool quality in advanced formulations.'),
('3b52f163-a4fe-4352-87c8-6d0ab6e92c40','Apple Pectin','Soluble Fiber','{"DOG","CAT"}', 'Use cautiously to avoid excessive stool softening.', 'Soluble fiber with gel-forming properties.', 'Can assist stool normalization and gut fermentation balance.'),
('5cf17006-cce4-4310-834d-64b4cac051ab','Blueberries','Supplement','{"DOG","CAT"}', 'Use modestly due to sugar load; not a major nutrient anchor.', 'Contain fiber, vitamin C, manganese, and polyphenol antioxidants.', 'Used as a low-volume antioxidant-rich addition or treat.'),
('ea68534a-664b-4c5d-b812-3d1d4f4dd15a','Strawberries','Supplement','{"DOG","CAT"}', 'Moderate due to natural sugars.', 'Supply vitamin C, fiber, and polyphenols.', 'Used occasionally as a fruit inclusion for enrichment and variety.'),
('c3c0ff77-71bc-4558-b920-6f27edb13b15','Apples','Supplement','{"DOG","CAT"}', 'Remove seeds and core; feed in moderation.', 'Provide fiber and modest vitamin C with relatively low fat.', 'Used mainly for low-calorie treat value and fiber contribution.'),
('9194ed76-b987-48ae-a759-4a68e5040781','Pears','Supplement','{"DOG","CAT"}', 'Remove seeds and core; use moderately due to sugar.', 'Contain water, fiber, and small amounts of copper and vitamin C.', 'Occasional fruit inclusion for variety and moisture.'),
('9600aeed-3700-435d-b909-17841fa700d1','Banana','Supplement','{"DOG","CAT"}', 'Use sparingly because of sugar and calorie density.', 'Provides potassium, carbohydrate, and some B6.', 'Sometimes used as a palatable binder or treat ingredient in small amounts.'),
('04aaaf84-d6ea-4dcb-9de8-63551fd62a25','Watermelon','Supplement','{"DOG","CAT"}', 'Remove seeds and rind; feed as a minor treat only.', 'High water content with low calorie density and modest lycopene-related phytonutrients.', 'Useful for hydration-oriented treat inclusion in hot weather.'),
('b6e263de-a9af-4dd0-b9d9-fb55cfb4f74c','Cantaloupe','Supplement','{"DOG","CAT"}', 'Feed small amounts and remove rind and seeds.', 'Contains water, beta-carotene, potassium, and vitamin C.', 'Occasional fruit addition for enrichment and hydration support.'),
