('70964f18-32c6-488e-a84a-82977ee7e377','Potassium Citrate','Supplement','{"DOG"}', 'Use only when clinically indicated; overuse can cause electrolyte imbalance.', 'Supplies potassium and urinary alkalinizing capacity.', 'Used in diets for selected urinary stone risk profiles or documented hypokalemia management.'),
('0045c40d-2b73-4a50-86c7-a15a9e426193','Magnesium Supplement','Supplement','{"DOG","CAT"}', 'Excessive magnesium may be undesirable in some urinary conditions.', 'Essential mineral involved in neuromuscular and enzymatic function.', 'Added when homemade formulation analysis shows magnesium shortfall.'),
('c6c5f0e9-5b88-4673-ab9b-8e2bcdb8a484','Manganese Supplement','Supplement','{"DOG","CAT"}', 'Do not guess-dose; use calculated inclusion only.', 'Trace mineral needed for cartilage, enzyme systems, and metabolism.', 'Frequently necessary in homemade diets because many base ingredients undersupply manganese.'),
('85cf9f5a-fabf-459b-8062-7614c52827cb','Selenium Supplement','Supplement','{"DOG","CAT"}', 'Overdose risk is real; use formulation-guided amounts only.', 'Trace mineral important for antioxidant enzyme systems and thyroid function.', 'Added where the ingredient set does not meet selenium targets.'),
('26c8f8dd-1b57-4dbe-a31f-f23afc4c27bc','Choline Supplement','Supplement','{"DOG","CAT"}', 'Use calculated amounts only; avoid arbitrary oversupplementation.', 'Supports phospholipid metabolism, methyl donation, and hepatic fat transport.', 'Important in homemade diets where choline adequacy may otherwise be inconsistent.'),
('9a076411-e034-4dc8-8f16-85c01aa487d0','Methionine Supplement','Supplement','{"DOG","CAT"}', 'Use only when formulation indicates need; excess sulfur amino acids are undesirable.', 'Sulfur-containing essential amino acid used in protein balance and urinary acidification contexts.', 'May be included to adjust amino acid profile or support selected urinary strategies.'),
('905d42bc-5ca2-4906-8683-6c0b67bb0934','Arginine Supplement','Supplement','{"CAT"}', 'Use only under formulated guidance; cats have an absolute arginine requirement.', 'Essential amino acid central to ammonia detoxification in the urea cycle.', 'Critical in feline nutrition where inadequate arginine can rapidly cause serious metabolic consequences.'),
('959f1ca0-a5c7-4255-ad58-00be3f0d98e6','Marine Algae Oil','Essential Fat','{"CAT"}', 'Use controlled dosing; does not replace complete formulation balancing.', 'Provides DHA and sometimes EPA depending on product, without fish protein.', 'Useful when feline diets need omega-3 support but fish ingredients are restricted.'),
('56d6a6cc-794a-4645-89ca-d49d6778e8fb','Cod Liver Oil','Supplement','{"DOG","CAT"}', 'Use very cautiously because vitamin A and D excess can occur.', 'Supplies omega-3 plus fat-soluble vitamins A and D in concentrated amounts.', 'Only appropriate when carefully dosed in a calculated formulation.'),
('47c95f2a-d565-4744-b289-1b8bc8715306','Gelatin','Supplement','{"DOG"}', 'Not a complete protein and should not replace core animal protein.', 'Collagen-derived protein with limited essential amino acid balance.', 'Used occasionally as a texture aid or adjunct in canine recipes, not as a primary protein source.'),
('329ba5d7-0640-4a6d-870e-5eb49b609d7a','Collagen Peptides','Supplement','{"DOG"}', 'Do not count as complete dietary protein.', 'Hydrolyzed collagen peptides with poor essential amino acid completeness.', 'Included in selected joint-supportive feeding approaches as an adjunct only.'),
('3d73054f-1940-4dc4-90d0-ed3b6ce034af','Nutritional Yeast','Supplement','{"DOG"}', 'Use unsalted plain products only and modestly to avoid excessive mineral distortion.', 'Contains B vitamins, some protein, and flavor-enhancing compounds.', 'Used in canine diets for palatability and B-vitamin enrichment.'),
('214c0f01-3aa8-4d8d-b1a0-4e2ac64d6f1d','Dicalcium Phosphate','Supplement','{"DOG","CAT"}', 'Use only when formulation indicates combined calcium and phosphorus adjustment is needed.', 'Provides both calcium and phosphorus in a predictable supplemental form.', 'Useful in balancing recipes that undersupply one or both major minerals.'),
('2cdab44f-7614-4a43-a5dc-6d48a04f0914','Choline Chloride','Supplement','{"DOG","CAT"}', 'Calculated inclusion only; not for casual kitchen use.', 'Concentrated choline source for hepatic and neurologic nutrition support.', 'Often employed in professionally balanced homemade formulas to meet choline targets.'),
('b55d8060-fb0b-421a-b131-367a915b0d51','Calcium Citrate','Supplement','{"DOG","CAT"}', 'Dose by formulation rather than estimation.', 'Supplemental calcium source with different elemental density than carbonate.', 'Used when calcium support is needed and specific formulation preferences favor citrate.'),
('cf988ff1-67f1-48fc-b25a-2495349ab1b1','Multivitamin Mineral Premix','Supplement','{"DOG","CAT"}', 'Select only veterinary-appropriate premixes; human products may be inappropriate or toxic.', 'Provides broad-spectrum vitamins and trace minerals to close formulation gaps.', 'Central to producing complete and balanced homemade diets rather than ingredient-only feeding.'),
('408f6c5a-1ff0-45e0-b0d3-85890e96db8a','Iron-Rich Heme Blend','Supplement','{"DOG","CAT"}', 'Use only with documented need or formulation shortfall; excess iron is harmful.', 'Provides highly bioavailable heme iron relative to many plant sources.', 'Used in selected anemia-supportive or iron-deficient formulations.'),
('c2d8ca32-4205-4ff4-87ee-8517e2cbf708','Omega-3 Concentrate','Essential Fat','{"DOG","CAT"}', 'Monitor total vitamin E support and oxidation risk when using concentrated oils.', 'High-density EPA/DHA supplement with strong anti-inflammatory potential.', 'Useful for therapeutic homemade diets targeting dermatologic, inflammatory, or joint support.'),
('669b9228-f89f-4a35-a942-72ed3419d919','Renal Egg White Base','Lean Protein','{"DOG","CAT"}', 'Egg white-heavy recipes require complete balancing and should not be fed without mineral/vitamin correction.', 'Very high biological value protein with low phosphorus relative to many meats.', 'Commonly favored in renal-supportive homemade planning when phosphorus reduction is needed while preserving protein quality.'),
('2394dc46-acf2-434b-b09d-b9f2cb121bb8','Low-Copper Protein Blend','Lean Protein','{"DOG"}', 'For copper-associated hepatopathy, avoid copper-rich organs such as liver and shellfish.', 'Built from lower-copper animal protein sources with reduced copper exposure.', 'Used in canine liver-supportive homemade formulations when copper restriction is a goal.'),
('5afdd287-3842-4428-8269-bf941a60d8e5','Low-Purine Protein Blend','Lean Protein','{"DOG"}', 'Avoid high-purine organs and some seafood in urate-prone dogs.', 'Uses lower-purine proteins such as egg, dairy adjuncts, and selected lean meats.', 'Designed for homemade plans supporting dogs predisposed to urate urolithiasis.'),
('380974af-b9db-43d5-bf5e-65dd45983339','Novel Protein Rotation Base','Lean Protein','{"DOG","CAT"}', 'Should be truly novel to the individual patient and used consistently during trials.', 'Typically built from rabbit, venison, duck, or kangaroo with complete amino acid support.', 'Used in elimination-style homemade diet planning for suspected food hypersensitivity.'),
('4e6f6589-1c17-4905-bc4d-a3f821924cba','High-Energy Working Dog Fat Blend','Essential Fat','{"DOG"}', 'Not appropriate for sedentary or pancreatitis-prone dogs.', 'Combination of animal fat and omega-support oils to increase caloric density substantially.', 'Applied in homemade diets for endurance, working, or underconditioned dogs needing dense caloric support.'),
('6a670fa4-ecc0-4f57-8faa-9b13f65ff475','Feline Carnivore Support Blend','Supplement','{"CAT"}', 'Must still be part of a fully balanced feline formula with taurine, arachidonic acid, vitamin A, and appropriate calcium.', 'Emphasizes animal tissue nutrients central to obligate carnivore nutrition.', 'Used conceptually in feline homemade formulation to ensure species-appropriate nutrient priorities are maintained.'),
('8eb8ebff-d8ff-462a-9324-e3fd2f1d4f99','Canine Digestive Transition Base','Complex Carb','{"DOG"}', 'Intended for short-term transition only unless fully balanced.', 'Built around digestible carbohydrate and lean protein with controlled fat and fiber.', 'Used when transitioning between foods or during short-term digestive recovery planning.'),
('0517b84e-56b2-42e0-85fd-20a57fc366cf','Feline Moisture Support Base','Lean Protein','{"CAT"}', 'Should remain nutritionally complete and not rely only on water dilution.', 'High-moisture animal-protein base supporting hydration and urinary tract goals.', 'Useful in feline homemade planning where water intake support and urine dilution are important.'),
('8af91263-e98e-4662-bfb3-d7f747ab1d1a','Joint Support Nutrient Pack','Supplement','{"DOG","CAT"}', 'Adjunct only and not a replacement for balanced macronutrients or veterinary care.', 'May combine omega-3 support, manganese adequacy, vitamin E, and selected joint adjuncts.', 'Included in homemade diets for aging or orthopedic patients where anti-inflammatory nutrient support is desired.'),
('1d2737ba-8cac-4ca2-8965-547ef6b0b3b2','Weight Management Fiber Pack','Soluble Fiber','{"DOG","CAT"}', 'Excess fiber can reduce digestibility and palatability if overused.', 'Combines soluble and insoluble fiber sources to increase satiety with limited calories.', 'Used in calorie-controlled homemade diets to support fullness and stool quality.'),
('5f9ad9ce-3676-4c4e-af4f-61bbd8424102','Performance Recovery Protein Mix','Lean Protein','{"DOG"}', 'Not needed in sedentary pets and must still be balanced for minerals and vitamins.', 'High-quality complete protein blend emphasizing digestibility and amino acid density.', 'Applied in active and sporting dog homemade diets to support recovery and lean mass maintenance.');
